package com.trustcapture.vendor.util

import android.content.Context
import android.security.keystore.KeyGenParameterSpec
import android.security.keystore.KeyProperties
import dagger.hilt.android.qualifiers.ApplicationContext
import java.io.File
import java.io.FileOutputStream
import java.security.KeyStore
import javax.crypto.Cipher
import javax.crypto.KeyGenerator
import javax.crypto.SecretKey
import javax.crypto.spec.GCMParameterSpec
import javax.inject.Inject
import javax.inject.Singleton

/**
 * Encrypts/decrypts files using AES-256-GCM with keys stored in Android Keystore.
 * Each encryption generates a unique 12-byte IV, prepended to the ciphertext.
 * Encrypted files are stored in app-private storage (not accessible to other apps).
 */
@Singleton
class EncryptionManager @Inject constructor(
    @ApplicationContext private val context: Context
) {
    companion object {
        private const val KEYSTORE_PROVIDER = "AndroidKeyStore"
        private const val KEY_ALIAS = "trustcapture_aes_key"
        private const val TRANSFORMATION = "AES/GCM/NoPadding"
        private const val GCM_IV_LENGTH = 12
        private const val GCM_TAG_LENGTH = 128
        private const val ENCRYPTED_DIR = "encrypted_photos"
    }

    private val keyStore: KeyStore by lazy {
        KeyStore.getInstance(KEYSTORE_PROVIDER).apply { load(null) }
    }

    private val encryptedDir: File by lazy {
        File(context.filesDir, ENCRYPTED_DIR).also { it.mkdirs() }
    }

    /**
     * Generates AES-256 key in Android Keystore if not already present.
     */
    fun ensureKeyExists() {
        if (keyStore.containsAlias(KEY_ALIAS)) return
        val spec = KeyGenParameterSpec.Builder(
            KEY_ALIAS,
            KeyProperties.PURPOSE_ENCRYPT or KeyProperties.PURPOSE_DECRYPT
        )
            .setBlockModes(KeyProperties.BLOCK_MODE_GCM)
            .setEncryptionPaddings(KeyProperties.ENCRYPTION_PADDING_NONE)
            .setKeySize(256)
            .build()

        KeyGenerator.getInstance(KeyProperties.KEY_ALGORITHM_AES, KEYSTORE_PROVIDER).apply {
            init(spec)
            generateKey()
        }
    }

    private fun getSecretKey(): SecretKey {
        ensureKeyExists()
        return (keyStore.getEntry(KEY_ALIAS, null) as KeyStore.SecretKeyEntry).secretKey
    }

    /**
     * Encrypts a photo file and stores it in app-private encrypted directory.
     * Returns the path to the encrypted file.
     * Format: [12-byte IV][ciphertext with GCM tag]
     */
    fun encryptPhoto(sourceFile: File): String {
        val cipher = Cipher.getInstance(TRANSFORMATION)
        cipher.init(Cipher.ENCRYPT_MODE, getSecretKey())
        val iv = cipher.iv // unique IV generated by Cipher

        val outputFile = File(encryptedDir, "${System.currentTimeMillis()}_${sourceFile.name}.enc")
        val plainBytes = sourceFile.readBytes()
        val encrypted = cipher.doFinal(plainBytes)

        FileOutputStream(outputFile).use { fos ->
            fos.write(iv) // prepend IV
            fos.write(encrypted)
        }
        return outputFile.absolutePath
    }

    /**
     * Decrypts an encrypted photo file back to plaintext bytes.
     */
    fun decryptPhoto(encryptedPath: String): ByteArray {
        val file = File(encryptedPath)
        val allBytes = file.readBytes()
        val iv = allBytes.copyOfRange(0, GCM_IV_LENGTH)
        val ciphertext = allBytes.copyOfRange(GCM_IV_LENGTH, allBytes.size)

        val cipher = Cipher.getInstance(TRANSFORMATION)
        cipher.init(Cipher.DECRYPT_MODE, getSecretKey(), GCMParameterSpec(GCM_TAG_LENGTH, iv))
        return cipher.doFinal(ciphertext)
    }

    /**
     * Deletes an encrypted file from storage.
     */
    fun deleteEncryptedFile(encryptedPath: String): Boolean {
        return File(encryptedPath).delete()
    }
}
